import {
  useContentList,
  useFastSchema,
  type RelationPickerProps,
} from "fastschema/react";
import { CirclePlusIcon } from "lucide-react";
import { Fragment } from "react/jsx-runtime";

import { Button } from "@/components/ui/button";
import {
  AlertError,
  getGlobalLinkComponent,
  Loading,
  titleCase,
} from "@/components/fsui/fscommon";
import { FsFilter } from "@/components/fsui/fsfilter";
import { FsTable } from "@/components/fsui/fstable/fstable";

import { useContentListColumns } from "./hooks/use-content-list-columns";
import { schemaError } from "./utils";

import type { ColumnDef } from "@tanstack/react-table";
import type { Entity, PKType, Schema } from "fastschema";
import type { ReactNode } from "react";

export type ContentListProps<T extends Entity> = Omit<
  RelationPickerProps,
  "relationField"
> & {
  filter?: Parameters<typeof useContentList>[0]["filter"];
  initialPagination: {
    page: number;
    limit: number;
  };
  createButton?: ReactNode;
  createEditLink?: (id: string | number) => string;
  onFilterChange?: (
    filter: Parameters<typeof useContentList>[0]["filter"],
  ) => void;
  onPaginationChange?: (page: number, limit: number) => void;
  createColumns?: (schema?: Schema) => ColumnDef<T>[];
};

export const ContentList = <T extends Entity>({
  schemaName,
  filter,
  initialPagination,
  createButton,
  createEditLink,
  onFilterChange,
  onPaginationChange,
  createColumns,
}: ContentListProps<T>) => {
  const Link = getGlobalLinkComponent();
  const { fastschema } = useFastSchema();
  const columns = useContentListColumns<T>({
    schemaName,
    createEditLink,
    createColumns,
  });
  const schema = fastschema.schema(schemaName);
  const label = titleCase(schemaName);

  const { result, isLoading, isFetching, error } = useContentList<T>({
    ...initialPagination,
    schemaName,
    filter,
  });

  if (error || !schema) {
    return <AlertError error={schemaError(schemaName, error)} />;
  }

  if (isLoading) {
    return <Loading />;
  }

  return (
    <Fragment>
      <div className="flex items-center justify-between gap-2">
        <div className="flex flex-col gap-1 px-1">
          <h2 className="text-xl font-semibold tracking-tight">{label} List</h2>
          <p className="text-muted-foreground">
            Manage your {label} entries here.
          </p>
        </div>
      </div>
      <div className="mt-5 px-1">
        <FsTable
          columns={columns}
          data={result?.items ?? []}
          className={isFetching ? "pointer-events-none opacity-50" : ""}
          pagination={{
            itemsPerPage: result?.per_page ?? 10,
            currentPage: result?.current_page || 1,
            totalItems: result?.total || 0,
            totalPages: result?.last_page || 1,
            onChange: onPaginationChange,
          }}
          getRowId={(originalRow) => {
            const pkColumn = schema?.definition().primary_field ?? "id";
            return originalRow[pkColumn] as PKType;
          }}
          actions={{
            left: (
              <div className="flex items-center justify-center gap-2">
                <FsFilter
                  schema={schema?.definition()}
                  value={filter}
                  onChange={onFilterChange}
                  storageKey={`content_${schemaName}`}
                  persist="localStorage"
                />
                {createButton || (
                  <Button
                    size="sm"
                    variant="outline"
                    asChild
                  >
                    <Link href={`/content/${schemaName}/create`}>
                      <CirclePlusIcon />
                      Create
                    </Link>
                  </Button>
                )}
              </div>
            ),
          }}
        />
      </div>
    </Fragment>
  );
};

import { isRelationField } from "fastschema";
import { useFastSchema } from "fastschema/react";

import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import {
  getGlobalLinkComponent,
  populateActiveListViewSettings,
} from "@/components/fsui/fscommon";
import { FsTableColumnHeader } from "@/components/fsui/fstable/column-header";

import type { ColumnDef } from "@tanstack/react-table";
import type { Entity, Schema } from "fastschema";
import type { ReactNode } from "react";

export const useContentListColumns = <T extends Entity>({
  schemaName,
  createEditLink,
  createColumns,
}: {
  schemaName: string;
  createEditLink?: (id: string | number) => string;
  createColumns?: (schema?: Schema) => ColumnDef<T>[];
}) => {
  const { fastschema } = useFastSchema();
  const Link = getGlobalLinkComponent();
  const schema = fastschema.schema(schemaName);
  if (!schema) {
    return [];
  }

  const definition = schema.definition();
  const activeListViewSettings = populateActiveListViewSettings(definition);

  if (createColumns) {
    return createColumns(schema);
  }

  const columns: ColumnDef<T>[] = [
    {
      id: "select",
      size: 50,
      enableSorting: false,
      enableHiding: false,
      enableResizing: false,
      header: ({ table }) => (
        <div className="px-2">
          <Checkbox
            checked={
              table.getIsAllPageRowsSelected() ||
              (table.getIsSomePageRowsSelected() && "indeterminate")
            }
            onCheckedChange={(value) =>
              table.toggleAllPageRowsSelected(!!value)
            }
            aria-label="Select all"
            className="translate-y-[2px] cursor-pointer"
          />
        </div>
      ),
      cell: ({ row }) => {
        return (
          <div className="px-2">
            <Checkbox
              checked={row.getIsSelected()}
              onCheckedChange={(value) => row.toggleSelected(!!value)}
              aria-label="Select row"
              className="translate-y-[2px] cursor-pointer"
            />
          </div>
        );
      },
    },
  ];

  for (const colSetting of activeListViewSettings) {
    const fieldDef = definition.fields.find((f) => f.name === colSetting.field);
    if (!fieldDef || colSetting.invisible) {
      continue;
    }

    const isPrimary = [definition.primary_field, "id"].includes(fieldDef.name);
    const includeColumns = [
      definition.primary_field,
      "id",
      definition.label_field,
      "created_at",
      "updated_at",
    ];

    if (fieldDef.immutable && !includeColumns.includes(fieldDef.name)) {
      continue;
    }

    let cellRender: ColumnDef<T>["cell"] = (cell) => (
      <span className="inline-block max-w-full overflow-hidden text-ellipsis whitespace-nowrap">
        {cell.getValue() as ReactNode}
      </span>
    );
    if (
      ["id", definition.primary_field, definition.label_field].includes(
        fieldDef.name,
      )
    ) {
      cellRender = ({ row, getValue }) => {
        const id = row.original[definition.primary_field ?? "id"] as
          | string
          | number;
        const editLink = createEditLink
          ? createEditLink(id)
          : `/content/${definition.name}/edit?id=${id}`;
        return (
          <Link
            className="text-primary inline-block max-w-full overflow-hidden font-medium text-ellipsis whitespace-nowrap hover:underline"
            href={editLink}
            title={`Edit ${row.original.name}`}
          >
            {getValue<string>()}
          </Link>
        );
      };
    }

    if (fieldDef.type === "bool") {
      cellRender = ({ getValue }) => (
        <Checkbox
          checked={!!getValue<boolean>()}
          disabled
          className="translate-y-[2px]"
        />
      );
    }

    if (fieldDef.type === "time") {
      cellRender = ({ getValue }) => {
        const val = getValue<string>();
        if (!val) {
          return "";
        }
        const date = new Date(val);
        return <span className="text-sm">{date.toLocaleString()}</span>;
      };
    }

    if (isRelationField(fieldDef)) {
      const relInfo = fastschema.relationInfo(fieldDef);
      cellRender = ({ getValue }) => {
        const relationValue = getValue<Record<string, unknown>>();
        const relationValues = Array.isArray(relationValue)
          ? relationValue
          : [relationValue];
        return (
          <div className="flex max-w-full flex-wrap space-y-1 space-x-1">
            {relationValues
              .map((rv) => {
                const val = rv?.[relInfo.labelCol];
                const relId = rv?.[relInfo.primaryCol];

                if (!val || !relId) {
                  return null;
                }

                if (fieldDef.type === "file") {
                  const url = rv?.["url"] as string | undefined;
                  return url ? (
                    <img
                      key={val + relId}
                      src={url}
                      alt={val as string}
                      className="max-h-8 max-w-8 rounded"
                    />
                  ) : null;
                }

                return (
                  <Badge
                    key={val + relId}
                    variant="secondary"
                    className="inline-block max-w-full overflow-hidden text-ellipsis whitespace-nowrap"
                  >
                    {val as string}
                  </Badge>
                );
              })
              .filter(Boolean)}
          </div>
        );
      };
    }

    columns.push({
      enableSorting: colSetting.sortable || isPrimary,
      enableHiding: !isPrimary,
      enableResizing: true,
      accessorKey: fieldDef.name,
      size: colSetting.max_width || 150,
      header: ({ column }) => <FsTableColumnHeader column={column} />,
      cell: cellRender,
    });
  }

  return columns;
};

import { useFastSchema } from "fastschema/react";

import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { getGlobalLinkComponent } from "@/components/fsui/fscommon";
import { FsTableColumnHeader } from "@/components/fsui/fstable/column-header";

import type { ColumnDef } from "@tanstack/react-table";
import type { Entity } from "fastschema";

export const useRelationContentColumns = ({
  schemaName,
}: {
  schemaName: string;
}) => {
  const { fastschema } = useFastSchema();
  const schema = fastschema.schema(schemaName);
  if (!schema) {
    return { tableColumns: [], dbColumns: [] };
  }

  const Link = getGlobalLinkComponent();
  const definition = schema.definition();
  const primaryField = definition.primary_field || "id";
  const labelField = definition.label_field;
  const tableColumns: ColumnDef<Entity>[] = [
    {
      id: "select",
      size: 50,
      enableSorting: false,
      enableHiding: false,
      enableResizing: false,
      header: ({ table }) => (
        <div className="px-2">
          <Checkbox
            checked={
              table.getIsAllPageRowsSelected() ||
              (table.getIsSomePageRowsSelected() && "indeterminate")
            }
            onCheckedChange={(value) =>
              table.toggleAllPageRowsSelected(!!value)
            }
            aria-label="Select all"
            className="translate-y-[2px] cursor-pointer"
          />
        </div>
      ),
      cell: ({ row }) => {
        return (
          <div className="px-2">
            <Checkbox
              checked={row.getIsSelected()}
              onCheckedChange={(value) => row.toggleSelected(!!value)}
              aria-label="Select row"
              className="translate-y-[2px] cursor-pointer"
            />
          </div>
        );
      },
    },
  ];

  if (primaryField) {
    tableColumns.push({
      enableSorting: false,
      enableHiding: false,
      enableResizing: false,
      accessorKey: primaryField,
      size: 60,
      header: ({ column }) => <FsTableColumnHeader column={column} />,
      cell: ({ row, getValue }) => {
        const id = row.original[definition.primary_field ?? "id"];
        return (
          <Link
            className="flex overflow-hidden"
            href={`/schemas/content/edit/${definition.name}?id=${id}`}
            title={row.original[primaryField] as string}
            target="_blank"
          >
            <Badge
              variant="outline"
              className="inline-block max-w-full overflow-hidden text-ellipsis whitespace-nowrap"
            >
              {getValue<string>()}
            </Badge>
          </Link>
        );
      },
    });
  }

  if (labelField) {
    tableColumns.push({
      enableSorting: false,
      enableHiding: true,
      enableResizing: false,
      accessorKey: labelField,
      size: 230,
      header: ({ column }) => <FsTableColumnHeader column={column} />,
      cell: ({ row, getValue }) => {
        const id = row.original[definition.primary_field ?? "id"];
        return (
          <Link
            className="text-primary inline-block max-w-full overflow-hidden font-medium text-ellipsis whitespace-nowrap hover:underline"
            href={`/schemas/content/edit/${definition.name}?id=${id}`}
            title={row.original[primaryField] as string}
            target="_blank"
          >
            {getValue<string>()}
          </Link>
        );
      },
    });
  }

  return {
    tableColumns,
    dbColumns: [primaryField, labelField || primaryField],
  };
};

export * from "./content-list";
export * from "./relation-picker";
export * from "./hooks/use-content-list-columns";

import { flexRender } from "@tanstack/react-table";
import {
  isNumericFieldType,
  type Entity,
  type Filter,
  type PKFieldType,
  type PKType,
} from "fastschema";
import { useContentList, useFastSchema } from "fastschema/react";
import { forwardRef, useImperativeHandle, useState } from "react";

import { cn } from "@/lib/utils";
import { AlertError, Loading } from "@/components/fsui/fscommon";
import { FsFilter } from "@/components/fsui/fsfilter";
import { FsTableBody } from "@/components/fsui/fstable/common";
import { FsTablePagination } from "@/components/fsui/fstable/pagination";

import { useFsTable } from "../fstable/use-fstable";

import { useRelationContentColumns } from "./hooks/use-relation-content-columns";
import { schemaError } from "./utils";

import type { ReactNode } from "react";

export interface RelationPickerListRef {
  refresh: () => void;
}

export interface RelationPickerListProps {
  schemaName: string;
  label?: ReactNode;
  initialFilter?: Filter;
  actions?: ReactNode;
  multiSelection?: boolean;
  onSelectionChange?: (selectedItems: Entity[]) => void;
}

export const RelationPickerList = forwardRef<
  RelationPickerListRef,
  RelationPickerListProps
>(
  (
    {
      schemaName,
      label,
      initialFilter,
      actions,
      multiSelection,
      onSelectionChange,
    },
    ref,
  ) => {
    const { fastschema } = useFastSchema();
    const [filter, setFilter] = useState<Filter>(initialFilter ?? {});
    const [pagination, setPagination] = useState({
      page: 1,
      limit: 10,
    });
    const schema = fastschema.schema(schemaName);
    const schemaDef = schema?.definition();
    const { tableColumns, dbColumns } = useRelationContentColumns({
      schemaName,
    });
    const pkCol = schemaDef?.primary_field ?? "id";
    const pkColIsNumber = isNumericFieldType(
      schemaDef?.fields.find((f) => f.name === pkCol)?.type as PKFieldType,
    );

    const query = useContentList({
      ...pagination,
      schemaName,
      filter,
      select: dbColumns,
    });

    const { table, columnSizeVars } = useFsTable({
      columns: tableColumns,
      data: query.result?.items || [],
      pagination: {
        totalItems: query.result?.total || 0,
        itemsPerPage: query.result?.per_page || 10,
        currentPage: query.result?.current_page || 1,
        totalPages: query.result?.last_page || 1,
        onChange: (page: number, limit: number) => {
          setPagination({ page, limit });
        },
      },
      getRowId: (originalRow) => originalRow[pkCol] as PKType,
      multiSelection,
      onRowSelectionChange: (selectedRowIds) => {
        const rowsById = table.getRowModel().rowsById;
        const selectedItems = Object.entries(selectedRowIds).flatMap(
          ([rowId, isSelected]) => {
            if (!isSelected) return [];
            const row = rowsById[rowId];
            return row
              ? [row.original]
              : [
                  {
                    [pkCol]: pkColIsNumber ? Number(rowId) : rowId,
                  },
                ];
          },
        );

        onSelectionChange?.(selectedItems);
      },
    });

    useImperativeHandle(ref, () => ({
      refresh: () => {
        query.reFetch();
        table.resetRowSelection();
      },
    }));

    if (query.error || !schema) {
      return <AlertError error={schemaError(schemaName, query.error)} />;
    }

    if (query.isLoading) {
      return <Loading />;
    }

    const firstHeaderGroup = table.getHeaderGroups()[0];
    const firstHeaderCol = firstHeaderGroup?.headers[0];
    return (
      <div
        data-slot="table"
        className="flex h-full min-h-0 w-full flex-1 flex-col"
        style={{
          ...columnSizeVars,
          width: table.getTotalSize(),
          minWidth: "100%",
        }}
      >
        <div
          data-slot="table-header"
          className="bg-sidebar"
        >
          <div
            data-slot="table-header-row"
            className="hover:bg-muted/50 data-[state=selected]:bg-muted flex items-center justify-between border-b px-2 py-1 transition-colors"
          >
            <div data-slot="table-header-cell">
              {flexRender(
                firstHeaderCol.column.columnDef.header,
                firstHeaderCol.getContext(),
              )}
            </div>
            <div
              data-slot="table-header-cell"
              className="flex items-center gap-2"
            >
              {label}
              <span>
                ({query.result?.total || 0} item
                {(query.result?.total || 0) === 1 ? "" : "s"})
              </span>
            </div>
            <div data-slot="table-header-cell">
              <FsFilter
                schema={schema?.definition()}
                value={filter}
                onChange={(f) => setFilter(f || {})}
                storageKey={`content_${schemaName}`}
                iconOnly
              />
            </div>
          </div>
        </div>
        <div
          className={cn(
            "flex min-h-0 flex-1 flex-col",
            query.isFetching ? "pointer-events-none opacity-50" : "",
          )}
        >
          <div className="flex flex-1 flex-col overflow-y-auto p-0">
            <FsTableBody table={table} />
          </div>
        </div>
        <div className="bg-sidebar flex items-end justify-between border-t px-3 py-2">
          {actions}
          <FsTablePagination
            table={table}
            minimal
          />
        </div>
      </div>
    );
  },
);

RelationPickerList.displayName = "RelationPickerList";

import {
  type RelationPickerProps,
  type RelationPickerRef,
  useRelationContentPicker,
} from "fastschema/react";
import {
  PinIcon,
  PinOffIcon,
  SettingsIcon,
  SquareDashedMousePointerIcon,
} from "lucide-react";
import { forwardRef, useImperativeHandle } from "react";
import { toast } from "sonner";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { FsDialog } from "@/components/fsui/fscommon/dialog";

import { AlertError } from "../fscommon";

import { RelationPickerList } from "./relation-picker-list";

export const RelationPicker = forwardRef<
  RelationPickerRef,
  RelationPickerProps
>((props, ref) => {
  const {
    open,
    schema,
    relationSchema,
    isSelectMode,
    isMany,
    isMutating,
    attachableItems,
    detachableItems,
    availableRecordsRef,
    connectedRecordsRef,
    selectedEntities,
    updateRelation,
    handleOpenChange,
    handleSelectionChange,
    handleConfirm,
    handleClear,
    setDetachableItems,
    setAttachableItems,
  } = useRelationContentPicker({
    onSuccess: (action, items) => {
      toast.success(`Successfully ${action}ed ${items.length} item(s)`);
    },
    onError: (action, error) => {
      toast.error(`Failed to ${action} items: ${error.message}`);
    },
    ...props,
  });

  // Expose updateRelation to parent via ref
  useImperativeHandle(
    ref,
    () => ({
      updateRelation,
    }),
    [updateRelation],
  );

  if (!schema || !relationSchema) {
    return (
      <AlertError
        error={new Error(`Schema "${props.schemaName}" not found.`)}
      />
    );
  }

  // Default trigger for select mode
  const defaultTrigger = (
    <Button
      variant="outline"
      size="sm"
      className="gap-2"
      disabled={props.disabled}
    >
      <SquareDashedMousePointerIcon />
      Select {props.relationField.relation.schema}
    </Button>
  );

  return (
    <div className={cn("max-w-full space-y-4", props.className)}>
      <FsDialog
        open={open}
        onOpenChange={handleOpenChange}
        hideFooter
        trigger={props.trigger || defaultTrigger}
        title={
          <Badge
            variant="outline"
            className="flex items-center justify-center gap-1 px-3 py-1 text-sm font-medium select-none"
          >
            <SettingsIcon className="size-4" />
            {isSelectMode
              ? `Select ${props.relationField.label || props.relationField.name}`
              : `Manage Related ${props.relationField.name}`}
          </Badge>
        }
      >
        {isSelectMode ? (
          // Select mode: single panel with selection
          <div className="flex h-full flex-col gap-3 text-sm">
            <RelationPickerList
              ref={availableRecordsRef}
              schemaName={props.relationField.relation.schema}
              label={<div className="font-medium">Records</div>}
              initialFilter={props.availableRecordsFilter}
              onSelectionChange={handleSelectionChange}
              multiSelection={isMany}
              actions={
                <div className="flex items-center gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={handleClear}
                    disabled={selectedEntities.length === 0}
                  >
                    Clear
                  </Button>
                  <Button
                    size="sm"
                    onClick={handleConfirm}
                  >
                    Confirm ({selectedEntities.length})
                  </Button>
                </div>
              }
            />
          </div>
        ) : (
          // Manage mode: two-panel UI with attach/detach
          <div className="flex h-full flex-row text-sm">
            <div className="h-full w-1/2">
              <RelationPickerList
                ref={connectedRecordsRef}
                schemaName={props.relationField.relation.schema}
                label={<div className="font-medium">Connected</div>}
                initialFilter={props.connectedRecordsFilter}
                multiSelection={isMany}
                onSelectionChange={setDetachableItems}
                actions={
                  <Button
                    size="sm"
                    variant="outline"
                    className="gap-2"
                    onClick={() => updateRelation("$clear", detachableItems)}
                    disabled={detachableItems.length === 0 || isMutating}
                  >
                    <PinOffIcon />
                    Detach
                  </Button>
                }
              />
            </div>
            <div className="h-full w-1/2 border-l">
              <RelationPickerList
                ref={availableRecordsRef}
                schemaName={props.relationField.relation.schema}
                label={<div className="font-medium">Available</div>}
                initialFilter={props.availableRecordsFilter}
                multiSelection={isMany}
                onSelectionChange={setAttachableItems}
                actions={
                  <Button
                    size="sm"
                    variant="outline"
                    className="gap-2"
                    onClick={() => updateRelation("$add", attachableItems)}
                    disabled={attachableItems.length === 0 || isMutating}
                  >
                    <PinIcon />
                    Attach
                  </Button>
                }
              />
            </div>
          </div>
        )}
      </FsDialog>
    </div>
  );
});

RelationPicker.displayName = "RelationPicker";

export const schemaError = (schemaName: string, error?: Error) => {
  return error || new Error(`Schema not found: ${schemaName ?? "unknown"}`);
};
